                setProfileData(data);
                setHasExistingRecord(true);
            }

            // 2. Fetch Resume Existence
            const { data: resumeCheck } = await supabase
                .from(table)
                .select('id')
                .eq('id', user.id)
                .not('resume', 'is', null)
                .single();

            setResumeUploaded(!!resumeCheck);

        } catch (error) {
            console.error("Failed to load profile", error);
        } finally {
            setFetching(false);
        }
    };
