const API_KEY = "AIzaSyDUo8NlOC56gWYEETviAceCUd-mxoruplQ";
const ai = new GoogleGenAI({ apiKey: API_KEY });

const MODELS = ["gemini-2.5-flash", "gemini-2.5-flash-latest"];

// --- 1. Data Aggregation (Adaptive: Summary OR Detailed) ---

export const fetchReportContext = async (config: ReportConfig) => {
    try {
        // 1. OPTIMIZED: Filter Users at DB Level first
        let studentQuery = supabase.from('students').select('id, first_name, last_name, program, year_level');
        let alumniQuery = supabase.from('alumni').select('id, first_name, last_name, program, year_level');

        if (config.batch !== 'All') {
            studentQuery = studentQuery.eq('year_level', config.batch);
            alumniQuery = alumniQuery.eq('year_level', config.batch);
        }
        if (config.program !== 'All') {
            studentQuery = studentQuery.eq('program', config.program);
            alumniQuery = alumniQuery.eq('program', config.program);
        }

        const [ studentRes, alumniRes ] = await Promise.all([
            studentQuery,
            alumniQuery
        ]);

        const students = studentRes.data || [];
        const alumni = alumniRes.data || [];

        const studentMap = new Map(students.map((s: any) => [s.id, s]));
        const alumniMap = new Map(alumni.map((a: any) => [a.id, a]));

        // 2. Fetch Survey Responses
        const studentIds = students.map((s: any) => s.id);
        const alumniIds = alumni.map((a: any) => a.id);

        if (studentIds.length === 0 && alumniIds.length === 0) {
            return { type: 'summary', totalGraduates: 0 };
        }

        const surveyPromises = [];
        // Chunking IDs to avoid URL too large errors if needed, but for now direct 'in'
        if (studentIds.length > 0) {
             surveyPromises.push(supabase.from('survey_responses').select('id, student_id, alumni_id, respondent_type').in('student_id', studentIds));
        }
        if (alumniIds.length > 0) {
             surveyPromises.push(supabase.from('survey_responses').select('id, student_id, alumni_id, respondent_type').in('alumni_id', alumniIds));
        }

        const surveyResults = await Promise.all(surveyPromises);
        const surveys = surveyResults.flatMap(r => r.data || []);

        // 3. Match Profiles & Build Valid List
        const validSurveys: any[] = [];
        const surveyIds: string[] = [];

        surveys.forEach((survey: any) => {
            let profile: any = null;
            if (survey.respondent_type === 'student') profile = studentMap.get(survey.student_id);
            else profile = alumniMap.get(survey.alumni_id);

            if (profile) {
                validSurveys.push({ ...survey, profile });
                surveyIds.push(survey.id);
            }
        });

        if (validSurveys.length === 0) return { type: 'summary', totalGraduates: 0 };

        // 4. Fetch All Related Data from Detailed Tables
        const [empRes, eduRes, commRes, attrRes] = await Promise.all([
            supabase.from('employment_information').select('*').in('survey_response_id', surveyIds),
            supabase.from('education_information').select('*').in('survey_response_id', surveyIds),
            supabase.from('community_engagement').select('*').in('survey_response_id', surveyIds),
            supabase.from('alumni_attributes').select('*').in('survey_response_id', surveyIds)
        ]);

        // Maps for O(1) Access
        const empMap = new Map<string, any>(empRes.data?.map((e: any) => [e.survey_response_id, e]) || []);
        const eduMap = new Map<string, any>(eduRes.data?.map((e: any) => [e.survey_response_id, e]) || []);
        const attrMap = new Map<string, any>(attrRes.data?.map((e: any) => [e.survey_response_id, e]) || []);

        const commMap = new Map<string, any[]>();
        commRes.data?.forEach((c: any) => {
            const list = commMap.get(c.survey_response_id) || [];
            list.push(c);
            commMap.set(c.survey_response_id, list);
        });

        // 5. Build Aggregates & Detailed Records
        let totalGraduates = validSurveys.length;
        const detailedRecords: any[] = [];

        // Aggregation Containers
        const statusCounts: Record<string, number> = {};
        const programCounts: Record<string, number> = {}; 
        const industryCounts: Record<string, number> = {};
        const jobLevelCounts: Record<string, number> = {};
        const alignmentCounts: Record<string, number> = {};
        const salaryCounts: Record<string, number> = {};

        // Education Aggregates
        const primarySchoolCounts: Record<string, number> = {};
        const secondarySchoolCounts: Record<string, number> = {};
        const degreesCounts: Record<string, number> = {};

        // Community Aggregates
        const orgCounts: Record<string, number> = {};
        const participationCount = { active: 0, inactive: 0 };

        // Skills Aggregates
        const attributeSums: Record<string, number> = {};
        const attributeResponseCounts: Record<string, number> = {};

        validSurveys.forEach(survey => {
            const profile = survey.profile;
            const emp = empMap.get(survey.id);
            const edu = eduMap.get(survey.id);
            const attr = attrMap.get(survey.id);
            const comms = commMap.get(survey.id) || [];

            // Basic Info
            const fullName = `${profile.first_name} ${profile.last_name}`;
            const status = emp?.employment_status || 'Unknown';
            const prog = profile.program || 'Unknown';

            // --- Aggregation (Standard Report) ---
            statusCounts[status] = (statusCounts[status] || 0) + 1;
            programCounts[prog] = (programCounts[prog] || 0) + 1;

            if (status === 'Employed' || status === 'Self-employed') {
                if (emp?.industry) industryCounts[emp.industry] = (industryCounts[emp.industry] || 0) + 1;
                if (emp?.current_job_level) jobLevelCounts[emp.current_job_level] = (jobLevelCounts[emp.current_job_level] || 0) + 1;
                if (emp?.job_alignment) alignmentCounts[emp.job_alignment] = (alignmentCounts[emp.job_alignment] || 0) + 1;
                const salary = emp?.salary_range || emp?.business_revenue;
                if (salary) salaryCounts[salary] = (salaryCounts[salary] || 0) + 1;
            }

            if (edu) {
                if (edu.primary_school) primarySchoolCounts[edu.primary_school] = (primarySchoolCounts[edu.primary_school] || 0) + 1;
                if (edu.secondary_school) secondarySchoolCounts[edu.secondary_school] = (secondarySchoolCounts[edu.secondary_school] || 0) + 1;
                if (edu.bachelors_degree) degreesCounts['Bachelors'] = (degreesCounts['Bachelors'] || 0) + 1;
                if (edu.masters_degree && edu.masters_degree !== 'None') degreesCounts['Masters'] = (degreesCounts['Masters'] || 0) + 1;
                if (edu.doctoral_degree && edu.doctoral_degree !== 'None') degreesCounts['Doctoral'] = (degreesCounts['Doctoral'] || 0) + 1;
            }

            if (comms.length > 0) {
                participationCount.active++;
                comms.forEach((c: any) => {
                    if (c.organization_name) orgCounts[c.organization_name] = (orgCounts[c.organization_name] || 0) + 1;
                });
            } else {
                participationCount.inactive++;
            }

            if (attr) {
                Object.keys(attr).forEach(key => {
                    if (key !== 'id' && key !== 'survey_response_id' && typeof attr[key] === 'number') {
                        attributeSums[key] = (attributeSums[key] || 0) + attr[key];
                        attributeResponseCounts[key] = (attributeResponseCounts[key] || 0) + 1;
                    }
                });
            }

            // --- Detailed Record Construction (Exact Mapping to Provided Schema) ---
            detailedRecords.push({
                // Personal
                id: survey.id, // Reference
                full_name: fullName,
                program: prog,
                batch: profile.year_level,

                // Employment Information
                employment_status: emp?.employment_status || null,
                job_alignment: emp?.job_alignment || null,
                current_position: emp?.current_position || null,
                date_hired: emp?.date_hired || null,
                company_name: emp?.company_name || null,
                company_address: emp?.company_address || null,
                current_job_level: emp?.current_job_level || null,
                first_job_level: emp?.first_job_level || null,
                time_to_first_job: emp?.time_to_first_job || null,
                business_name: emp?.business_name || null,
                business_address: emp?.business_address || null,
                business_type: emp?.business_type || null,
                business_contact_no: emp?.business_contact_no || null,
                unemployed_reasons: emp?.unemployed_reasons || null,
                last_company: emp?.last_company || null,
                retirement_reason: emp?.retirement_reason || null,
                date_retired: emp?.date_retired || null,
                industry: emp?.industry || null,
                business_duration: emp?.business_duration || null,
                alignment_reason: emp?.alignment_reason || null,
                employment_type: emp?.employment_type || null,
                business_revenue: emp?.business_revenue || null,
                salary_range: emp?.salary_range || null,

                // Education Information
                primary_school: edu?.primary_school || null,
                primary_year_graduated: edu?.primary_year_graduated || null,
                secondary_school: edu?.secondary_school || null,
                secondary_year_graduated: edu?.secondary_year_graduated || null,
                bachelors_degree: edu?.bachelors_degree || null,
                bachelors_year_graduated: edu?.bachelors_year_graduated || null,
                masters_degree: edu?.masters_degree || null,
                masters_year_graduated_or_units: edu?.masters_year_graduated_or_units || null,
                doctoral_degree: edu?.doctoral_degree || null,
                doctoral_year_graduated_or_units: edu?.doctoral_year_graduated_or_units || null,
                professional_license: edu?.professional_license || null,
                license_date_passed: edu?.license_date_passed || null,
                license_number: edu?.license_number || null,

                // Community Engagement (Aggregated)
                community_engagements: comms.map((c: any) => ({
                    organization_name: c.organization_name,
                    role: c.role,
                    date_affiliated: c.date_affiliated
                })),

                // Alumni Attributes (Skills)
                attributes: attr ? {
                    professionally_competent: attr.professionally_competent,
                    critical_thinker: attr.critical_thinker,
                    communicator: attr.communicator,
                    lifelong_learner: attr.lifelong_learner,
                    socially_responsible: attr.socially_responsible,
                    ethical_citizen: attr.ethical_citizen,
                    innovative_worker: attr.innovative_worker,
                    people_oriented: attr.people_oriented,
                    critical_thinking_skill: attr.critical_thinking_skill,
                    creativity: attr.creativity,
                    collaboration: attr.collaboration,
                    communication_skill: attr.communication_skill,
                    information_literacy: attr.information_literacy,
                    media_literacy: attr.media_literacy,
                    technology_literacy: attr.technology_literacy,
                    flexibility: attr.flexibility,
                    leadership: attr.leadership,
                    initiative: attr.initiative,
                    productivity: attr.productivity,
                    social_skills: attr.social_skills
                } : null
            });
        });

        // Compute Attribute Averages
        const attributeAverages: Record<string, string> = {};
        Object.keys(attributeSums).forEach(key => {
            attributeAverages[key] = (attributeSums[key] / attributeResponseCounts[key]).toFixed(2);
        });

        const topPrimary = Object.entries(primarySchoolCounts).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 5);
        const topSecondary = Object.entries(secondarySchoolCounts).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 5);
        const topOrgs = Object.entries(orgCounts).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 5);

        // Always return detailed records for custom reports or high fidelity analysis
        return {
            type: config.type === 'Custom' ? 'detailed' : 'summary',
            totalGraduates,
            records: detailedRecords, // Detailed list of all fields

            // Summaries for Standard Reports
            statusCounts,
            programCounts,
            industryCounts,
            jobLevelCounts,
            alignmentCounts,
            salaryCounts,
            topPrimary,
            topSecondary,
            degreesCounts,
            topOrgs,
            participationCount,
            attributeAverages
        };

    } catch (error) {
        console.error("Context fetch error:", error);
        // Return empty structure instead of crashing
        return { type: 'summary', totalGraduates: 0, records: [] };
    }
};

// --- 2. AI Generation ---

const reportSchema: Schema = {
    type: Type.OBJECT,
    properties: {
        title: { type: Type.STRING },
        sections: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    title: { type: Type.STRING },
                    type: { type: Type.STRING, enum: ['text', 'table', 'bar-chart', 'pie-chart'] },
                    content: { type: Type.STRING, description: "For 'text': Plain text string. For 'table'/'chart': JSON string of array." }
                }
            }
        }
    }
};

export const generateAIReport = async (config: ReportConfig, contextData: any): Promise<ReportContent> => {

    // Determine Output Mode
    const hasNarrative = config.formats.includes('Narrative');
    const hasTable = config.formats.includes('Table') || config.formats.includes('Graph');

    let styleInstruction = "";

    if (hasNarrative && hasTable) {
        styleInstruction = "For each section, provide a **Detailed Analysis Paragraph** followed by the **Structured Data (Table/Chart)**.";
    } else if (hasNarrative) {
        styleInstruction = "For each section, provide ONLY detailed narrative analysis text. Do not generate JSON data arrays.";
    } else {
        styleInstruction = "For each section, provide the **Structured Data (Table/Chart)** AND a **Brief Explanation** (1-2 sentences max).";
    }

    let prompt = "";

    // --- PROMPT STRATEGY: CUSTOM REPORT ---
    if (contextData.type === 'detailed') {
        const recordsJson = JSON.stringify(contextData.records);
        prompt = `
            Act as a Data Analyst for Laguna University.

            **TASK:** Generate a specific Custom Report based on the user's request.

            **USER REQUEST:** "${config.customPrompt}"
            **STYLE:** ${styleInstruction}

            **DATA SCHEMA & RAW RECORDS:**
            The raw data includes full details for Employment (salary, revenue, history), Education (schools, licenses), Community, and Skills.

            ${recordsJson}

            **RULES:**
            1. Filter the raw data strictly based on the user request.
            2. If they ask for 'list of...', generate a table.
            3. If they ask for 'counts' or 'statistics', generate charts or tables.
            4. **CRITICAL:** Output strictly plain text for text content. For tables/charts, output a JSON array string inside the 'content' field.

            **OUTPUT:** JSON matching schema.
        `;
    } 
    // --- PROMPT STRATEGY: STANDARD REPORT ---
    else {
        // Use the aggregated summaries to save token space
        const { records, ...summaries } = contextData; // Exclude raw records
        const dataSample = JSON.stringify(summaries); 

        const getSecTitle = (name: string, metric: string) => {
            if (hasNarrative && hasTable) return `${name} (Detailed Text + Table of ${metric})`;
            if (hasNarrative) return `${name} (Detailed Text Analysis)`;
            return `${name} (Table of ${metric} + Brief Explanation)`;
        };

        let requiredSections = "";
        if (config.type === 'Employment') {
            requiredSections = `
            1. EXECUTIVE SUMMARY
            2. ${getSecTitle('EMPLOYMENT STATUS', 'statusCounts')}
            3. ${getSecTitle('TOP INDUSTRIES', 'industryCounts')}
            4. ${getSecTitle('JOB ALIGNMENT', 'alignmentCounts')}
            5. ${getSecTitle('SALARY RANGES', 'salaryCounts')}`;
        } else if (config.type === 'Education') {
            requiredSections = `
            1. EXECUTIVE SUMMARY
            2. ${getSecTitle('DEGREE ATTAINMENT', 'degreesCounts')}
            3. ${getSecTitle('TOP PRIMARY FEEDER SCHOOLS', 'primarySchoolCounts')}
            4. ${getSecTitle('TOP SECONDARY FEEDER SCHOOLS', 'secondarySchoolCounts')}`;
        } else if (config.type === 'Community') {
            requiredSections = `
            1. EXECUTIVE SUMMARY
            2. ${getSecTitle('PARTICIPATION RATE', 'participationCount')}
            3. ${getSecTitle('TOP ORGANIZATIONS', 'orgCounts')}`;
        } else if (config.type === 'Skills') {
            requiredSections = `
            1. EXECUTIVE SUMMARY
            2. ${getSecTitle('SKILLS ASSESSMENT', 'attributeAverages')}`;
        } else {
            // 'All'
            requiredSections = `
            1. EXECUTIVE SUMMARY
            2. ${getSecTitle('EMPLOYMENT STATUS', 'statusCounts')}
            3. ${getSecTitle('TOP INDUSTRIES', 'industryCounts')}
            4. ${getSecTitle('TOP FEEDER SCHOOLS', 'primarySchoolCounts')}
            5. ${getSecTitle('SKILLS OVERVIEW', 'attributeAverages')}`;
        }

        prompt = `
            Act as a Data Analyst for Laguna University. Generate a report based on the provided **Summary Statistics**.

            **Report Type:** ${config.type}
            **Filters:** Batch ${config.batch}, Program ${config.program}

            **Data Context:**
            ${dataSample}

            **STRICT GENERATION RULES:**
            1. **STYLE:** ${styleInstruction}
            2. **NO MARKDOWN**: Output strictly plain text for text sections.
            3. **CHARTS/TABLES**: If a section requires data, provide it as a JSON Array string in the 'content' field.
               - Format: [{"name": "Category", "value": 10}, ...]
            4. **SPEED**: Be concise and direct.

            **REQUIRED SECTIONS:**
            ${requiredSections}
        `;
    }

    for (const model of MODELS) {
        try {
            const result = await ai.models.generateContent({
                model: model,
                contents: { parts: [{ text: prompt }] },
                config: {
                    responseMimeType: "application/json",
                    responseSchema: reportSchema
                }
            });

            if (result.text) {
                const parsed = JSON.parse(result.text);
                const rawSections = Array.isArray(parsed.sections) ? parsed.sections : [];

                const sections = rawSections.map((sec: any) => {
                    // Safety check: Try parsing content if it looks like JSON array string
                    if ((sec.type === 'table' || sec.type.includes('chart')) && typeof sec.content === 'string') {
                        try {
                            const parsedContent = JSON.parse(sec.content);
                            return { ...sec, content: parsedContent };
                        } catch (e) {
                            // If parsing fails, default to empty array to prevent crash
                            return { ...sec, content: [] };
                        }
                    }
                    if (sec.type === 'text' && typeof sec.content === 'string') {
                        let cleanText = sec.content.replace(/\*\*/g, '').replace(/__/g, '').replace(/##/g, '');
                        sec.content = cleanText;
                    }
                    return sec;
                });

                return {
                    title: parsed.title || `${config.type} Report`,
                    generatedAt: new Date().toISOString(),
                    filters: { batch: config.batch, program: config.program },
                    sections: sections
                };
            }
        } catch (e) {
            console.error(`Model ${model} failed`, e);
        }
    }

    throw new Error("Failed to generate report.");
};

