export const saveReport = async (adminId: string, content: ReportContent, type: string) => {
    const jsonString = JSON.stringify(content);

    // Base payload with 'content' as fallback
    const payload: any = {
        admin_id: adminId,
        content: jsonString
    };

    // Determine target column based on type
    const normalizedType = type.toLowerCase();

    if (['employment', 'education', 'community', 'skills'].includes(normalizedType)) {
        payload[normalizedType] = jsonString;
    }

    const { error } = await supabase.from('reports').insert([payload]);
    if (error) throw error;
};

export const getReportHistory = async (adminId: string): Promise<GeneratedReport[]> => {
    const { data, error } = await supabase
        .from('reports')
        .select('*')
        .eq('admin_id', adminId)
        .order('created_at', { ascending: false });

    if (error) throw error;

    return data.map((row: any) => ({
        ...row,
        parsedContent: JSON.parse(row.content)
    }));
};

export const deleteReport = async (reportId: string) => {
    const { error } = await supabase
        .from('reports')
        .delete()
        .eq('id', reportId);
    if (error) throw error;
};

export const deleteAllReports = async (adminId: string) => {
    const { error } = await supabase
        .from('reports')
        .delete()
        .eq('admin_id', adminId);
    if (error) throw error;
};

import React from 'react';
import { GeneratedReport, ReportSection } from '../../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';
import { Download, FileText } from 'lucide-react';
import jsPDF from 'jspdf';

interface ReportPreviewProps {
  report: GeneratedReport;
}

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];

const ReportPreview: React.FC<ReportPreviewProps> = ({ report }) => {
  const content = report.parsedContent;

  if (!content) return <div>Invalid Report Data</div>;

  const handleDownloadPDF = () => {
      // Basic print-to-pdf trigger for browser
      window.print();
  };

  const renderSection = (section: ReportSection, index: number) => {
      switch (section.type) {
          case 'text':
              return (
                  <div key={index} className="mb-6 text-slate-700 break-inside-avoid">
                      {section.title && <h4 className="text-lg font-bold text-slate-800 mb-2 uppercase tracking-wide border-l-4 border-orange-500 pl-3">{section.title}</h4>}
                      <div className="whitespace-pre-wrap text-sm leading-relaxed text-slate-700 pl-1">
                          {typeof section.content === 'string' ? section.content : JSON.stringify(section.content)}
                      </div>
                  </div>
              );
          case 'table':
              // CRITICAL FIX: Ensure content is an array before mapping
              const rows = Array.isArray(section.content) ? section.content : [];

              if (rows.length === 0) {
                  return (
                      <div key={index} className="mb-8 p-4 bg-gray-50 border border-dashed border-gray-300 rounded text-center text-xs text-gray-500">
                          {section.title} - No data available for table.
                      </div>
                  );
              }

              const headers = Object.keys(rows[0] || {});
              if (headers.length === 0) return null;

              return (
                  <div key={index} className="mb-8 overflow-x-auto break-inside-avoid">
                      {section.title && <h4 className="text-lg font-bold text-slate-800 mb-3 uppercase tracking-wide border-l-4 border-emerald-500 pl-3">{section.title}</h4>}
                      <table className="w-full text-sm text-left border-collapse bg-white rounded-xl shadow-sm overflow-hidden border border-slate-200">
                          <thead className="bg-slate-100 text-slate-700 font-bold uppercase text-xs">
                              <tr>
                                  {headers.map(h => <th key={h} className="px-4 py-3 border-b border-slate-200">{h}</th>)}
                              </tr>
                          </thead>
                          <tbody className="divide-y divide-slate-100">
                              {rows.map((row: any, i: number) => (
                                  <tr key={i} className={`hover:bg-slate-50 ${row[headers[0]] === 'TOTAL' ? 'bg-slate-50 font-bold' : ''}`}>
                                      {headers.map(h => (
                                          <td key={h} className="px-4 py-2 border-r border-slate-100 last:border-r-0">
                                              {typeof row[h] === 'object' ? JSON.stringify(row[h]) : row[h]}
                                          </td>
                                      ))}
                                  </tr>
                              ))}
                          </tbody>
                      </table>
                  </div>
              );
          case 'bar-chart':
              // CRITICAL FIX: Check array
              const barData = Array.isArray(section.content) ? section.content : [];
              if (barData.length === 0) return null;

              return (
                  <div key={index} className="mb-8 break-inside-avoid">
                      {section.title && <h4 className="text-lg font-bold text-slate-800 mb-3 uppercase tracking-wide border-l-4 border-blue-500 pl-3">{section.title}</h4>}
                      <div className="h-80 bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                          <ResponsiveContainer width="100%" height="100%">
                              <BarChart data={barData}>
                                  <CartesianGrid strokeDasharray="3 3" opacity={0.3} />
                                  <XAxis dataKey="name" tick={{fontSize: 10}} />
                                  <YAxis />
                                  <Tooltip />
                                  <Bar dataKey="value" fill="#3b82f6" radius={[4,4,0,0]} />
                              </BarChart>
                          </ResponsiveContainer>
                      </div>
                  </div>
              );
          case 'pie-chart':
              // CRITICAL FIX: Check array
              const pieData = Array.isArray(section.content) ? section.content : [];
              if (pieData.length === 0) return null;

              return (
                  <div key={index} className="mb-8 break-inside-avoid">
                      {section.title && <h4 className="text-lg font-bold text-slate-800 mb-3 uppercase tracking-wide border-l-4 border-purple-500 pl-3">{section.title}</h4>}
                      <div className="h-80 bg-white p-4 rounded-xl border border-slate-100 shadow-sm flex justify-center">
                          <ResponsiveContainer width="100%" height="100%">
                              <PieChart>
                                  <Pie
                                      data={pieData}
                                      cx="50%"
                                      cy="50%"
                                      outerRadius={80}
                                      fill="#8884d8"
                                      dataKey="value"
                                      label
                                  >
                                      {pieData.map((entry: any, index: number) => (
                                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                      ))}
                                  </Pie>
                                  <Tooltip />
                                  <Legend />
                              </PieChart>
                          </ResponsiveContainer>
                      </div>
                  </div>
              );
          default:
              return null;
      }
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden">
        {/* Toolbar */}
        <div className="bg-slate-800 text-white p-4 flex justify-between items-center no-print">
            <div className="flex items-center gap-2">
                <FileText size={20} />
                <span className="font-bold">Report Preview</span>
            </div>
            <button onClick={handleDownloadPDF} className="bg-orange-500 hover:bg-orange-600 px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-colors">
                <Download size={16} /> Print / Save PDF
            </button>
        </div>

        {/* Paper */}
        <div className="p-8 md:p-12 min-h-[800px] bg-white print:p-0">
            <div className="border-b-2 border-slate-800 pb-6 mb-8 flex justify-between items-end">
                <div>
                    <h1 className="text-3xl font-black text-slate-900 uppercase tracking-tight">{content.title}</h1>
                    <p className="text-slate-500 mt-2 font-medium">Generated: {new Date(content.generatedAt).toLocaleString()}</p>
                </div>
                <div className="text-right text-xs font-bold text-slate-400 uppercase">
                    <p>Laguna University</p>
                    <p>Alumni Tracer System</p>
                </div>
            </div>

            <div className="flex gap-4 mb-8 text-xs font-bold uppercase tracking-wider text-slate-500 bg-slate-50 p-3 rounded-lg border border-slate-100">
                <span>Filter Batch: {content.filters.batch}</span>
                <span>•</span>
                <span>Filter Program: {content.filters.program}</span>
            </div>

            <div>
                {content.sections && Array.isArray(content.sections) ? (
                    content.sections.map((section, index) => renderSection(section, index))
                ) : (
                    <div className="text-red-500 font-bold">Error: Report sections missing or malformed.</div>
                )}
            </div>

            <div className="mt-12 pt-6 border-t border-slate-100 text-center text-xs text-slate-400 font-mono">
                *** End of Report ***
            </div>
        </div>
    </div>
  );
};

