// --- 1. Data Aggregation (Adaptive: Summary OR Detailed) ---

export const fetchReportContext = async (config: ReportConfig) => {
    try {
        // 1. OPTIMIZED: Filter Users at DB Level first
        let studentQuery = supabase.from('students').select('id, first_name, last_name, program, year_level');
        let alumniQuery = supabase.from('alumni').select('id, first_name, last_name, program, year_level');

        if (config.batch !== 'All') {
            studentQuery = studentQuery.eq('year_level', config.batch);
            alumniQuery = alumniQuery.eq('year_level', config.batch);
        }
        if (config.program !== 'All') {
            studentQuery = studentQuery.eq('program', config.program);
            alumniQuery = alumniQuery.eq('program', config.program);
        }

        const [ studentRes, alumniRes ] = await Promise.all([
            studentQuery,
            alumniQuery
        ]);

        const students = studentRes.data || [];
        const alumni = alumniRes.data || [];

        const studentMap = new Map(students.map((s: any) => [s.id, s]));
        const alumniMap = new Map(alumni.map((a: any) => [a.id, a]));

        // 2. Fetch Survey Responses
        const studentIds = students.map((s: any) => s.id);
        const alumniIds = alumni.map((a: any) => a.id);

        if (studentIds.length === 0 && alumniIds.length === 0) {
            return { type: 'summary', totalGraduates: 0 };
        }

        const surveyPromises = [];
        if (studentIds.length > 0) {
             surveyPromises.push(supabase.from('survey_responses').select('id, student_id, alumni_id, respondent_type').in('student_id', studentIds));
        }
        if (alumniIds.length > 0) {
             surveyPromises.push(supabase.from('survey_responses').select('id, student_id, alumni_id, respondent_type').in('alumni_id', alumniIds));
        }

        const surveyResults = await Promise.all(surveyPromises);
        const surveys = surveyResults.flatMap(r => r.data || []);

        // 3. Match Profiles & Build Valid List
        const validSurveys: any[] = [];
        const surveyIds: string[] = [];

        surveys.forEach((survey: any) => {
            let profile: any = null;
            if (survey.respondent_type === 'student') profile = studentMap.get(survey.student_id);
            else profile = alumniMap.get(survey.alumni_id);

            if (profile) {
                validSurveys.push({ ...survey, profile });
                surveyIds.push(survey.id);
            }
        });

        if (validSurveys.length === 0) return { type: 'summary', totalGraduates: 0 };

        // 4. Fetch All Related Data from Detailed Tables
        const [empRes, eduRes, commRes, attrRes] = await Promise.all([
            supabase.from('employment_information').select('*').in('survey_response_id', surveyIds),
            supabase.from('education_information').select('*').in('survey_response_id', surveyIds),
            supabase.from('community_engagement').select('*').in('survey_response_id', surveyIds),
            supabase.from('alumni_attributes').select('*').in('survey_response_id', surveyIds)
        ]);

        // Maps for O(1) Access
        const empMap = new Map<string, any>(empRes.data?.map((e: any) => [e.survey_response_id, e]) || []);
        const eduMap = new Map<string, any>(eduRes.data?.map((e: any) => [e.survey_response_id, e]) || []);
        const attrMap = new Map<string, any>(attrRes.data?.map((e: any) => [e.survey_response_id, e]) || []);

        const commMap = new Map<string, any[]>();
        commRes.data?.forEach((c: any) => {
            const list = commMap.get(c.survey_response_id) || [];
            list.push(c);
            commMap.set(c.survey_response_id, list);
        });

        // 5. Build Aggregates & Detailed Records
        let totalGraduates = validSurveys.length;
        const detailedRecords: any[] = [];

        // Aggregation Containers
        const statusCounts: Record<string, number> = {};
        const programCounts: Record<string, number> = {}; 
        const industryCounts: Record<string, number> = {};
        const jobLevelCounts: Record<string, number> = {};
        const alignmentCounts: Record<string, number> = {};
        const salaryCounts: Record<string, number> = {};

        const primarySchoolCounts: Record<string, number> = {};
        const secondarySchoolCounts: Record<string, number> = {};
        const degreesCounts: Record<string, number> = {};

        const orgCounts: Record<string, number> = {};
        const participationCount = { active: 0, inactive: 0 };

        const attributeSums: Record<string, number> = {};
        const attributeResponseCounts: Record<string, number> = {};

        validSurveys.forEach(survey => {
            const profile = survey.profile;
            const emp = empMap.get(survey.id);
            const edu = eduMap.get(survey.id);
            const attr = attrMap.get(survey.id);
            const comms = commMap.get(survey.id) || [];

            const fullName = `${profile.first_name} ${profile.last_name}`;
            const status = emp?.employment_status || 'Unknown';
            const prog = profile.program || 'Unknown';

            // Aggregation
            statusCounts[status] = (statusCounts[status] || 0) + 1;
            programCounts[prog] = (programCounts[prog] || 0) + 1;

            if (status === 'Employed' || status === 'Self-employed') {
                if (emp?.industry) industryCounts[emp.industry] = (industryCounts[emp.industry] || 0) + 1;
                if (emp?.current_job_level) jobLevelCounts[emp.current_job_level] = (jobLevelCounts[emp.current_job_level] || 0) + 1;
                if (emp?.job_alignment) alignmentCounts[emp.job_alignment] = (alignmentCounts[emp.job_alignment] || 0) + 1;
                const salary = emp?.salary_range || emp?.business_revenue;
                if (salary) salaryCounts[salary] = (salaryCounts[salary] || 0) + 1;
            }

            if (edu) {
                if (edu.primary_school) primarySchoolCounts[edu.primary_school] = (primarySchoolCounts[edu.primary_school] || 0) + 1;
                if (edu.secondary_school) secondarySchoolCounts[edu.secondary_school] = (secondarySchoolCounts[edu.secondary_school] || 0) + 1;
                if (edu.bachelors_degree) degreesCounts['Bachelors'] = (degreesCounts['Bachelors'] || 0) + 1;
                if (edu.masters_degree && edu.masters_degree !== 'None') degreesCounts['Masters'] = (degreesCounts['Masters'] || 0) + 1;
                if (edu.doctoral_degree && edu.doctoral_degree !== 'None') degreesCounts['Doctoral'] = (degreesCounts['Doctoral'] || 0) + 1;
            }

            if (comms.length > 0) {
                participationCount.active++;
                comms.forEach((c: any) => {
                    if (c.organization_name) orgCounts[c.organization_name] = (orgCounts[c.organization_name] || 0) + 1;
                });
            } else {
                participationCount.inactive++;
            }

            if (attr) {
                Object.keys(attr).forEach(key => {
                    if (key !== 'id' && key !== 'survey_response_id' && typeof attr[key] === 'number') {
                        attributeSums[key] = (attributeSums[key] || 0) + attr[key];
                        attributeResponseCounts[key] = (attributeResponseCounts[key] || 0) + 1;
                    }
                });
            }

            detailedRecords.push({
                id: survey.id,
                full_name: fullName,
                program: prog,
                batch: profile.year_level,
                employment_status: emp?.employment_status || null,
                job_alignment: emp?.job_alignment || null,
                current_position: emp?.current_position || null,
                company_name: emp?.company_name || null,
                industry: emp?.industry || null,
                salary_range: emp?.salary_range || null,
            });
        });

        const attributeAverages: Record<string, string> = {};
        Object.keys(attributeSums).forEach(key => {
            attributeAverages[key] = (attributeSums[key] / attributeResponseCounts[key]).toFixed(2);
        });

        const topPrimary = Object.entries(primarySchoolCounts).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 5);
        const topSecondary = Object.entries(secondarySchoolCounts).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 5);
        const topOrgs = Object.entries(orgCounts).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 5);

        return {
            type: config.type === 'Custom' ? 'detailed' : 'summary',
            totalGraduates,
            records: detailedRecords, 
            statusCounts,
            programCounts,
            industryCounts,
            jobLevelCounts,
            alignmentCounts,
            salaryCounts,
            topPrimary,
            topSecondary,
            degreesCounts,
            topOrgs,
            participationCount,
            attributeAverages
        };

    } catch (error) {
        console.error("Context fetch error:", error);
        return { type: 'summary', totalGraduates: 0, records: [] };
    }
};

// --- 2. AI Generation ---

// Updated Schema to handle text and data separately, preventing "JSON string inside JSON" errors
const reportSchema: Schema = {
    type: Type.OBJECT,
    properties: {
        title: { type: Type.STRING },
        sections: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    title: { type: Type.STRING },
                    type: { type: Type.STRING, enum: ['text', 'table', 'bar-chart', 'pie-chart'] },
                    textContent: { type: Type.STRING, description: "If type is 'text', provide the narrative here." },
                    chartData: { 
                        type: Type.ARRAY, 
                        description: "If type is 'table', 'bar-chart' or 'pie-chart', provide the data here.",
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                name: { type: Type.STRING },
                                value: { type: Type.NUMBER },
                                label: { type: Type.STRING, description: "Optional display label if different from name" }
                            }
                        }
                    }
                }
            }
        }
    }
};

export const generateAIReport = async (config: ReportConfig, contextData: any): Promise<ReportContent> => {

    // Determine Output Mode
    const hasNarrative = config.formats.includes('Narrative');

    let styleInstruction = "";
    if (hasNarrative) {
        styleInstruction = "For each section, provide a concise analysis/narrative in 'textContent'. If a chart/table is required, ALSO provide the 'chartData'.";
    } else {
        styleInstruction = "For each section, provide ONLY 'chartData' for tables/charts. Leave 'textContent' empty or very brief.";
    }

    // --- PROMPT STRATEGY ---
    const { records, ...summaries } = contextData; 
    const dataContext = contextData.type === 'detailed' ? JSON.stringify(records.slice(0, 50)) : JSON.stringify(summaries);

    const prompt = `
        Act as a Data Analyst for Laguna University. Generate a report.

        **Report Type:** ${config.type}
        **Filters:** Batch ${config.batch}, Program ${config.program}
        **Style:** ${styleInstruction}

        **Data Context:**
        ${dataContext}

        **INSTRUCTIONS:**
        1. **Structure:** Create sections based on the report type.
        2. **Text:** Put all narrative text in the 'textContent' field.
        3. **Data:** Put all numbers/counts for tables and charts in the 'chartData' array (name/value pairs). 
           - **DO NOT** stringify the JSON. Return actual JSON objects in the array.
        4. **Cleanliness:** Do not include the prompt or instructions in the output title or text.

        **REQUIRED SECTIONS (Based on Type):**
        - If 'Employment': Employment Status, Top Industries, Job Alignment, Salary Ranges.
        - If 'Education': Degree Attainment, Top Schools.
        - If 'Community': Participation Rate, Top Orgs.
        - If 'Skills': Skills Assessment (convert averages to 1-5 scale).
    `;

    for (const model of MODELS) {
        try {
            const result = await ai.models.generateContent({
                model: model,
                contents: { parts: [{ text: prompt }] },
                config: {
                    responseMimeType: "application/json",
                    responseSchema: reportSchema
                }
            });

            if (result.text) {
                const parsed = JSON.parse(result.text);
                const rawSections = Array.isArray(parsed.sections) ? parsed.sections : [];

                // Map back to the generic 'content' field expected by UI
                const sections = rawSections.map((sec: any) => {
                    let finalContent: any = "";

                    if (sec.type === 'text') {
                        finalContent = sec.textContent || "";
                    } else {
                        // For tables/charts, use chartData if available, otherwise fallback
                        finalContent = Array.isArray(sec.chartData) ? sec.chartData : [];
                    }

                    return {
                        title: sec.title,
                        type: sec.type,
                        content: finalContent
                    };
                });

                return {
                    title: parsed.title || `${config.type} Report`,
                    generatedAt: new Date().toISOString(),
                    filters: { batch: config.batch, program: config.program },
                    sections: sections
                };
            }
        } catch (e) {
            console.error(`Model ${model} failed`, e);
        }
    }

    throw new Error("Failed to generate report.");
};

