// A. Standard Report (Constant Layout + AI Interpretation)
const generateStandardReport = async (config: ReportConfig, context: any): Promise<ReportContent> => {

    // 1. Generate Interpretation Text with AI
    let interpretation = "Analysis unavailable.";
    try {
        const prompt = `
            Act as a Data Analyst. Write a 2-paragraph Executive Summary for a ${config.type} Report.

            Context: Laguna University Alumni Tracer.
            Filters: Batch ${config.batch}, Program ${config.program}.

            Data Statistics:
            ${JSON.stringify(context.stats)}

            Highlight key findings, dominant trends, and areas for improvement.
            Output PLAIN TEXT only. No markdown formatting like **bold** or # headings.
        `;

        const result = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: { parts: [{ text: prompt }] }
        });

        if (result.text) interpretation = result.text;
    } catch (e) {
        console.error("AI Text Gen failed", e);
    }

    // 2. Build Sections Programmatically (Constant Layout)
    const sections: ReportSection[] = [];

    // Executive Summary (AI Generated)
    sections.push({
        title: "Executive Summary",
        type: "text",
        content: interpretation
    });

    // Sections based on Type
    if (config.type === 'Employment' || config.type === 'All') {
        sections.push({
            title: "Employment Status Distribution",
            type: "pie-chart",
            content: context.stats.status
        });
        sections.push({
            title: "Top Industries",
            type: "bar-chart",
            content: context.stats.industry.slice(0, 10)
        });
        sections.push({
            title: "Job Alignment",
            type: "pie-chart",
            content: context.stats.alignment
        });
        sections.push({
            title: "Salary / Income Ranges",
            type: "bar-chart",
            content: context.stats.salary
        });
        // Data Table
        if (config.formats.includes('Table')) {
            sections.push({
                title: "Detailed Employment Data",
                type: "table",
                content: context.records.map((r: any) => ({
                    Name: r.full_name,
                    Status: r.status,
                    Position: r.position,
                    Company: r.company,
                    Salary: r.salary
                }))
            });
        }
    }

    if (config.type === 'Education' || config.type === 'All') {
        sections.push({
            title: "Educational Attainment",
            type: "bar-chart",
            content: context.stats.degrees
        });
    }

    if (config.type === 'Community' || config.type === 'All') {
        sections.push({
            title: "Community Participation Rate",
            type: "pie-chart",
            content: context.stats.participation
        });
    }

    if (config.type === 'Skills' || config.type === 'All') {
        sections.push({
            title: "Graduate Attributes Assessment (Avg 1-5)",
            type: "bar-chart",
            content: context.stats.attributes.slice(0, 10) // Top 10 skills
        });
    }

    return {
        title: `Official ${config.type} Report`,
        generatedAt: new Date().toISOString(),
        filters: { batch: config.batch, program: config.program },
        sections: sections
    };
};

// B. Custom Report (Pure AI)
const generateCustomReport = async (config: ReportConfig, context: any): Promise<ReportContent> => {
    // Simplified schema for custom requests
    const customSchema: Schema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            sections: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        type: { type: Type.STRING, enum: ['text', 'table'] },
                        textContent: { type: Type.STRING },
                        // For tables, asking for array of objects directly
                        tableData: { 
                            type: Type.ARRAY, 
                            items: { type: Type.OBJECT, properties: { col1: {type:Type.STRING}, col2: {type:Type.STRING} }, additionalProperties: true } 
                        } 
                    }
                }
            }
        }
    };

    const prompt = `
        Generate a Custom Report based on this user prompt: "${config.customPrompt}"

        Data Context (First 50 records):
        ${JSON.stringify(context.records.slice(0, 50))}

        If the user asks for a list, generate a 'table' section using 'tableData'.
        If the user asks for analysis, generate a 'text' section using 'textContent'.
    `;

    const result = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: { parts: [{ text: prompt }] },
        config: { responseMimeType: "application/json", responseSchema: customSchema }
    });

    if (result.text) {
        const parsed = JSON.parse(result.text);
        return {
            title: parsed.title,
            generatedAt: new Date().toISOString(),
            filters: { batch: config.batch, program: config.program },
            sections: parsed.sections.map((s: any) => ({
                title: s.title,
                type: s.type,
                content: s.type === 'table' ? s.tableData : s.textContent
            }))
        };
    }
    throw new Error("AI Generation Failed");
};

// --- Main Generator Function ---

export const generateAIReport = async (config: ReportConfig, contextData: any): Promise<ReportContent> => {
    if (config.type === 'Custom') {
        return generateCustomReport(config, contextData);
    } else {
        return generateStandardReport(config, contextData);
    }
};

// --- Database Operations ---

export const saveReport = async (adminId: string, content: ReportContent, type: string) => {
    const jsonString = JSON.stringify(content);
    const payload: any = { admin_id: adminId, content: jsonString };
    const normalizedType = type.toLowerCase();

    if (['employment', 'education', 'community', 'skills'].includes(normalizedType)) {
        payload[normalizedType] = jsonString;
    }

    const { error } = await supabase.from('reports').insert([payload]);
    if (error) throw error;
};

export const getReportHistory = async (adminId: string): Promise<GeneratedReport[]> => {
    const { data, error } = await supabase
        .from('reports')
        .select('*')
        .eq('admin_id', adminId)
        .order('created_at', { ascending: false });

    if (error) throw error;

    return data.map((row: any) => ({
        ...row,
        parsedContent: JSON.parse(row.content)
    }));
};

export const deleteReport = async (reportId: string) => {
    const { error } = await supabase.from('reports').delete().eq('id', reportId);
    if (error) throw error;
};

export const deleteAllReports = async (adminId: string) => {
    const { error } = await supabase.from('reports').delete().eq('admin_id', adminId);
    if (error) throw error;
};

